def are_similar_chars(x, y):
    if x == y:
        return True
    if (x == '1' and y == 'l') or (x == 'l' and y == '1'):
        return True
    if (x == '0' and y == 'o') or (x == 'o' and y == '0'):
        return True
    return False

def main():
    import sys
    input = sys.stdin.read().split()
    N = int(input[0])
    S = input[1]
    T = input[2]

    for s_char, t_char in zip(S, T):
        if not are_similar_chars(s_char, t_char):
            print("No")
            return
    print("Yes")

if __name__ == "__main__":
    main()
